var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"관측소, 본부의 파견 부대다.","JPN":"観測所、応答せよ。こちらは本部の派遣部隊だ。","ENG":"Observation Post, this is the reinforcement from HQ.","TWN":"觀測站，這裡是總部派遣部隊。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_UI_DECK_UNIIT_SELECT"},{"id":"L3_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"본 중대는 현재 맥크레디 포인트를 향해 이동 중.","JPN":"本中隊は現在、マクレディーポイントに向かって移動中。","ENG":"We're currently on our way to the MacCready Point.","TWN":"本中隊目前正向麥克蕾蒂要點移動中。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"관측소. 응답 바란다. 관측소.","JPN":"観測所、応答せよ。観測所。","ENG":"Observation Post. Come in, Observation Post.","TWN":"觀測站。請回答。觀測站。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"관측소는 아직 응답이 없나?","JPN":"観測所はまだ応答なしか？","ENG":"Still no response from the Observation Post?","TWN":"觀測站現在還沒有回應嗎？"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"네. 계속 교신을 시도하고 있지만 아무 반응 없습니다.","JPN":"ええ。何度も交信を試みていますが、反応がありません。","ENG":"No. We've been trying for some time now, but to no avail.","TWN":"是的。雖然我一直在嘗試通信，但他們沒有任何反應。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"나쁜 예감이 드는군......","JPN":"嫌な予感がするな……","ENG":"This doesn't feel good.","TWN":"真有種不好的預感啊……"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"대원들에게 조심하라고 전해 주게.","JPN":"隊員たちに警戒するよう伝えてくれ。","ENG":"Tell the men to be extra careful.","TWN":"告訴隊員們要小心。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"맥크레디 포인트가 그렇게 위험한 곳입니까?","JPN":"マクレディーポイントはそんなに危険なんですか？","ENG":"Is MacCready Point that dangerous of a place?","TWN":"麥克蕾蒂要點是那麼危險的地方嗎？"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"브리핑에서 아무 얘기 안 해 주던가?","JPN":"打ち合わせで聞いてないか？","ENG":"Didn't they tell you at the briefing?","TWN":"任務說明什麼都沒講嗎？"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"멸종 위기종이 사는 철새 서식지라고 들었습니다.","JPN":"絶滅危惧種の渡り鳥の生息地だと聞きました。","ENG":"I was told it was a habitat for endangered migratory birds.","TWN":"我聽說那裡是瀕臨滅絕的候鳥棲息地。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 금칙 사항은 이면세계보다 몇 배나 많더군요.","JPN":"ですが、禁則事項は裏世界より何倍も多いようでしたね。","ENG":"But then, there are several times more operational restraints than in Counterside operations.","TWN":"然而那裡的禁止事項比在異界還要多出幾倍。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"혹시 기관이 위험한 아티팩트라도 보관해 두는 곳입니까?","JPN":"もしかして、機関が危険なアーティファクトでも保管している場所なんですか？","ENG":"Is it where the Institution keeps dangerous artifacts?","TWN":"難道是機關保管危險人造神器的地方嗎？"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"귀띔도 안 해 주고 보내다니, 작전부가 요새 좀 까탈스러워졌군.","JPN":"何も教えずに送り込むとは、作戦部もこのところ面倒なことになっているようだな。","ENG":"They're not letting the troops in on it before sending them away? The Operation Department must be very wary these days.","TWN":"竟然都沒有提醒，作戰部最近有點不像話啊。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"맥크레디 포인트는 말하자면 버뮤다 삼각지대 같은 곳이야.","JPN":"マクレディーポイントは言ってみれば、バミューダトライアングルのような場所なんだ。","ENG":"In short, MacCready Point is the Bermuda Triangle, only on land.","TWN":"說起麥克蕾蒂要點，就如同百慕達三角洲那樣的地方。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"한 번 발을 잘못 들이면 영영 돌아올 수 없게 되지.","JPN":"下手に足を踏み入れると、二度と出られなくなる。","ENG":"Take one wrong step, and you'll be gone forever.","TWN":"一旦走錯一步，就再也回不來了。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"버뮤다 삼각지대요? 그건 그냥 헛소문이라고 알고 있는데요.","JPN":"バミューダトライアングルですか？　あれって都市伝説のようなものなのでは？","ENG":"Bermuda Triangle? I thought it was an urban legend.","TWN":"百慕達三角洲？我以為那只是個謠言。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"정확해. 하지만 맥크레디 포인트는 그게 사실이라는 점이 다르지.","JPN":"その通りだ。だが、マクレディーポイントは都市伝説ではなく、事実なんだ。","ENG":"It is. But MacCready Point is as real as it gets.","TWN":"沒錯。但麥克蕾蒂要點卻是真的。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"맥크레디 포인트는 <color=#ffd34c>학회</color>라는 조직의 거점일세.","JPN":"マクレディーポイントは<color=#ffd34c>学会</color>という組織の拠点になっていてな。","ENG":"MacCready Point is the base of an organization called <color=#ffd34c>the Society</color>.","TWN":"麥克蕾蒂要點是一個叫作<color=#ffd34c>學會</color>的組織據點。"},"stage":{"bg":"SS_ESPR_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"극비사항이라 모두 말해 줄 수는 없지만, 우리 프리드웬 기관의 오랜 숙적이지.","JPN":"極秘事項だから全てを話すわけにはいかないが、我々プリドウェン機関の古くからの宿敵でもある。","ENG":"A lot of it is confidential, so I can't tell you everything. All you need to know is the Society is the archenemy of Prydwen Institution.","TWN":"因為是機密事項所以沒辦法全部告訴你，但他們和我們普利多溫機關是長年的宿敵。"},"stage":{"bg":"SS_ESPR_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"관측소도 놈들의 동향을 파악하기 위해 설치해 둔 거고.","JPN":"観測所も奴らの動向を把握するために設置されたんだ。","ENG":"The Observation Post was set up there to keep an eye on their movement.","TWN":"觀測站也是為了把握那些傢伙的動向設置的。"},"stage":{"bg":"SS_ESPR_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그런데 갑자기 그곳에서 문제가 생겼다는 정보를 입수했거든.","JPN":"ところが、突然そこで問題が起きたという情報が入り……","ENG":"And they recently reported that there was something going on in the area.","TWN":"但突然，我們收到了那裡發生問題的情報。"},"stage":{"bg":"SS_ESPR_02","bgm":"THEMA_PRYDWEN","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"그래서 직접 문제를 확인하러 이렇게 날아가는 중이지.","JPN":"直接問題を確認するために、こうして駆けつけたというわけだ。","ENG":"Hence we're flying there, to see if it's anything serious.","TWN":"所以為了親自確認問題，我們才會像這樣趕過去。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"어때, 설명이 좀 되었나?","JPN":"どうだ、これで少しは説明になったか？","ENG":"Was that enough of an explanation?","TWN":"怎麼樣，有解釋到你的問題嗎？"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"COMMANDER_PRYDWEN_NULL_NULL","text":{"KOREA":"깊이 알려고 하면 다친다는 뜻이군요. 잘 이해했습니다.","JPN":"深く知ろうとすれば痛い目に合うということですね。よくわかりました。","ENG":"You're saying I'd get hurt if I try to know too much. Understood.","TWN":"想要深入了解就會受傷的意思吧，我理解了。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"젊은 친구가 눈치도 좋군. 마음에 들어.","JPN":"若いのに、空気も読めるみたいだな。気に入ったぞ。","ENG":"You catch on quick, young fella. I like it.","TWN":"年紀輕輕倒是挺會察言觀色的。我喜歡。"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"관측소에 근무하던 친구들도 자네처럼 눈치가 좋았어야 할 텐데......","JPN":"観測所で働いていた奴らも、君のように空気が読めればいいんだが……","ENG":"I wish the folks at the Observation Post had been as quick witted as you.","TWN":"在觀測站工作的朋友也該和你一樣，會察言觀色才對啊……"},"stage":{"bg":"HELI_NIGHT","bgm":"THEMA_PRYDWEN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};